class _KaleidoscopePainter extends CustomPainter {
  _KaleidoscopePainter({
    required this.mirrorAngleDegrees,
    required this.numberOfMirrors,
    required this.animationValue,
  });

  final double mirrorAngleDegrees;
  final int numberOfMirrors;
  final double animationValue;

  @override
  void paint(Canvas canvas, Size size) {
    final center = Offset(size.width / 2, size.height / 2);
    final radius = size.width * 0.42;

    canvas.drawCircle(
      center,
      radius,
      Paint()
        ..color = const Color(0xFF1E293B)
        ..style = PaintingStyle.stroke
        ..strokeWidth = 3,
    );

    final colors = [
      const Color(0xFFEF4444),
      const Color(0xFFF97316),
      const Color(0xFFEAB308),
      const Color(0xFF22C55E),
      const Color(0xFF3B82F6),
      const Color(0xFF8B5CF6),
    ];

    if (numberOfMirrors == 2) {
      final angleRad = (mirrorAngleDegrees * math.pi) / 180;
      for (var i = 0; i < 12; i++) {
        final rotation = i * (math.pi / 6) + (animationValue * 2 * math.pi);
        _drawMirrorLine(
          canvas,
          center,
          radius,
          rotation,
          angleRad,
          colors[i % colors.length],
        );
      }
    } else {
      final angleRad = (360 / numberOfMirrors) * math.pi / 180;
      for (var i = 0; i < numberOfMirrors; i++) {
        _drawMirrorLine(
          canvas,
          center,
          radius,
          i * angleRad,
          angleRad,
          colors[i % colors.length],
        );
      }

      for (var i = 0; i < numberOfMirrors; i++) {
        final color = colors[i % colors.length];
        final angle = (i * angleRad) + (math.pi / 2) - (angleRad / 2);
        final patternRadius = radius * 0.5;
        _drawColorBlob(
          canvas,
          Offset(
            center.dx + patternRadius * math.cos(angle),
            center.dy + patternRadius * math.sin(angle),
          ),
          12 + (i * 4),
          color,
        );
      }
    }

    canvas.drawCircle(
      center,
      6,
      Paint()
        ..color = Colors.white
        ..style = PaintingStyle.fill,
    );
  }

  void _drawMirrorLine(
    Canvas canvas,
    Offset center,
    double radius,
    double rotation,
    double angle,
    Color color,
  ) {
    final halfAngle = angle / 2;
    final startX = center.dx + radius * math.cos(rotation - halfAngle);
    final startY = center.dy + radius * math.sin(rotation - halfAngle);
    final endX = center.dx + radius * math.cos(rotation + halfAngle);
    final endY = center.dy + radius * math.sin(rotation + halfAngle);

    canvas.drawLine(
      Offset(startX, startY),
      Offset(endX, endY),
      Paint()
        ..color = color.withValues(alpha: 0.6)
        ..strokeWidth = 2,
    );
  }

  void _drawColorBlob(Canvas canvas, Offset center, double size, Color color) {
    canvas.drawCircle(
      center,
      size,
      Paint()
        ..color = color
        ..style = PaintingStyle.fill,
    );
  }

  @override
  bool shouldRepaint(covariant _KaleidoscopePainter oldDelegate) =>
      oldDelegate.mirrorAngleDegrees != mirrorAngleDegrees ||
      oldDelegate.numberOfMirrors != numberOfMirrors ||
      oldDelegate.animationValue != animationValue;
}

