        ..color = const Color(0xFF334155)
        ..strokeWidth = 2,
    );

    final arcPaint = Paint()
      ..color = const Color(0xFF7C3AED)
      ..strokeWidth = 2
      ..style = PaintingStyle.stroke;

    canvas.drawArc(
      Rect.fromCenter(center: Offset(cx, cy), width: 60, height: 60),
